+	case "ErrFrameTooLarge":
+		return errors.Is(err, contract.ErrFrameTooLarge)
+	case "SubprocessExitError":
+		var exitErr *adapter.SubprocessExitError
+		return errors.As(err, &exitErr)
+	default:
+		return false
+	}
+}
